SELECT state, total_hospitalized
FROM hospitalization_data
WHERE total_hospitalized > 1000;

SELECT DISTINCT state 
FROM hospitalization_data 
WHERE total_hospitalized > (SELECT AVG(total_hospitalized) FROM hospitalization_data);

SELECT state, total_positive_cases AS max_positive_cases
FROM case_data
WHERE total_positive_cases = (
    SELECT MAX(total_positive_cases) 
    FROM case_data
);

SELECT c.state, c.total_positive_cases
FROM case_data c
WHERE c.total_positive_cases > (SELECT AVG(total_positive_cases) FROM case_data);

SELECT total_deaths 
FROM death_data 
WHERE age_group = '65+' AND state = 'New York';

SELECT state, total_positive_cases
FROM case_data
ORDER BY total_positive_cases DESC;

SELECT SUM(total_deaths)
FROM death_data
WHERE state = 'California';

SELECT state, SUM(total_deaths) AS Total_Deaths, AVG(death_percentage) AS Average_Death_Percentage
FROM death_data
GROUP BY state;

SELECT state, positive_tests, negative_tests
FROM testing_data
WHERE positive_tests > negative_tests;
